| MCP:umysWT | plugins {
| MCP:umysWT |     id 'java-library'
| MCP:umysWT |     id 'org.springframework.boot' apply(false)
| MCP:umysWT |     id 'io.spring.dependency-management'
| MCP:umysWT |     id 'io.spring.javaformat' apply(false)
| MCP:umysWT |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:umysWT | }
| MCP:umysWT | 
| MCP:umysWT | apply from: 'lint.gradle'
| MCP:umysWT | 
| MCP:umysWT | allprojects {
| MCP:umysWT |     group = "${projectGroup}"
| MCP:umysWT |     version = "${applicationVersion}"
| MCP:umysWT | 
| MCP:umysWT |     repositories {
| MCP:umysWT |         mavenCentral()
| MCP:umysWT |     }
| MCP:umysWT | }
| MCP:umysWT | 
| MCP:umysWT | subprojects {
| MCP:umysWT |     apply plugin: 'java-library'
| MCP:umysWT |     apply plugin: 'org.springframework.boot'
| MCP:umysWT |     apply plugin: 'io.spring.dependency-management'
| MCP:umysWT |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:umysWT |     
| MCP:umysWT |     dependencyManagement {
| MCP:umysWT |         imports {
| MCP:umysWT |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:umysWT |         }
| MCP:umysWT |     }
| MCP:umysWT | 
| MCP:umysWT |     dependencies {
| MCP:umysWT |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:umysWT |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:umysWT |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:umysWT |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:umysWT |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:umysWT |         testImplementation 'org.assertj:assertj-core'
| MCP:umysWT |         testImplementation 'org.mockito:mockito-core'
| MCP:umysWT |     }
| MCP:umysWT | 
| MCP:umysWT |     java {
| MCP:umysWT |         toolchain {
| MCP:umysWT |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:umysWT |         }
| MCP:umysWT |     }
| MCP:umysWT | 
| MCP:umysWT |     bootJar.enabled = false
| MCP:umysWT |     jar.enabled = true
| MCP:umysWT | 
| MCP:umysWT |     test {
| MCP:umysWT |         useJUnitPlatform {
| MCP:umysWT |             excludeTags 'develop', 'restdocs'
| MCP:umysWT |         }
| MCP:umysWT |     }
| MCP:umysWT | 
| MCP:umysWT |     testing {
| MCP:umysWT |         suites {
| MCP:umysWT |             test {
| MCP:umysWT |                 targets {
| MCP:umysWT |                     unitTest {
| MCP:umysWT |                         testTask.configure {
| MCP:umysWT |                             group = 'verification'
| MCP:umysWT |                             useJUnitPlatform {
| MCP:umysWT |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:umysWT |                             }
| MCP:umysWT |                         }
| MCP:umysWT |                     }
| MCP:umysWT | 
| MCP:umysWT |                     contextTest {
| MCP:umysWT |                         testTask.configure {
| MCP:umysWT |                             group = 'verification'
| MCP:umysWT |                             useJUnitPlatform {
| MCP:umysWT |                                 includeTags 'context'
| MCP:umysWT |                             }
| MCP:umysWT |                         }
| MCP:umysWT |                     }
| MCP:umysWT | 
| MCP:umysWT |                     restDocsTest {
| MCP:umysWT |                         testTask.configure {
| MCP:umysWT |                             group = 'verification'
| MCP:umysWT |                             useJUnitPlatform {
| MCP:umysWT |                                 includeTags 'restdocs'
| MCP:umysWT |                             }
| MCP:umysWT |                         }
| MCP:umysWT |                     }
| MCP:umysWT | 
| MCP:umysWT |                     developTest {
| MCP:umysWT |                         testTask.configure {
| MCP:umysWT |                             group = 'verification'
| MCP:umysWT |                             useJUnitPlatform {
| MCP:umysWT |                                 includeTags 'develop'
| MCP:umysWT |                             }
| MCP:umysWT |                         }
| MCP:umysWT |                     }
| MCP:umysWT |                 }
| MCP:umysWT |             }
| MCP:umysWT |         }
| MCP:umysWT |     }
| MCP:umysWT | 
| MCP:umysWT |     tasks.named('asciidoctor').configure {
| MCP:umysWT |         dependsOn restDocsTest
| MCP:umysWT |     }
| MCP:umysWT | }

| MCP:umysWT | dependencies {
| MCP:umysWT |     implementation project(':core:core-enum')
| MCP:umysWT |     api 'org.springframework.boot:spring-boot-starter-data-jpa'
| MCP:umysWT |     runtimeOnly 'com.mysql:mysql-connector-j'
| MCP:umysWT |     runtimeOnly 'com.h2database:h2'
| MCP:umysWT | }

| MCP:umysWT | dependencies {
| MCP:umysWT |     implementation 'org.springframework.boot:spring-boot-starter-opentelemetry'
| MCP:umysWT |     implementation "io.sentry:sentry-logback:${property("sentryVersion")}"
| MCP:umysWT | }

| MCP:umysWT | dependencies {
| MCP:umysWT |     implementation 'org.springframework.boot:spring-boot-starter-actuator'
| MCP:umysWT |     runtimeOnly 'io.micrometer:micrometer-registry-prometheus'
| MCP:umysWT | }

| MCP:umysWT | dependencies {
| MCP:umysWT |     api 'org.springframework.boot:spring-boot-restdocs'
| MCP:umysWT |     api 'org.springframework.restdocs:spring-restdocs-mockmvc'
| MCP:umysWT |     compileOnly 'org.junit.jupiter:junit-jupiter-api'
| MCP:umysWT | }
